mapper.select:
SELECT id, log_code as logCode, log_name as logName, log_type as logType,
       module_name as moduleName, description, is_enabled as isEnabled,
       retention_days as retentionDays, is_del as isDel,
       create_date as createDate, update_date as updateDate
FROM sys_operation_log_definition
WHERE is_del = 0

    AND (log_code LIKE CONCAT('%', #{keyword}, '%') OR log_name LIKE CONCAT('%', #{keyword}, '%'))


    AND log_type = #{logType}


    AND module_name = #{moduleName}


    AND is_enabled = #{isEnabled}

ORDER BY create_date DESC

    LIMIT #{offset}, #{pageSize}

SELECT COUNT(*) FROM sys_operation_log_definition
WHERE is_del = 0

    AND (log_code LIKE CONCAT('%', #{keyword}, '%') OR log_name LIKE CONCAT('%', #{keyword}, '%'))


    AND log_type = #{logType}


    AND module_name = #{moduleName}


    AND is_enabled = #{isEnabled}

