SELECT id, log_code as logCode, user_id as userId, user_name as userName,
       organ_id as organId, organ_name as organName,
       operation_type as operationType, operation_module as operationModule,
       operation_desc as operationDesc, request_method as requestMethod,
       request_url as requestUrl, ip_address as ipAddress,
       status, error_msg as errorMsg, execution_time as executionTime,
       create_date as createDate
FROM sys_operation_log
WHERE is_del = 0

    AND log_code = #{logCode}


    AND user_id = #{userId}


    AND user_name LIKE CONCAT('%', #{userName}, '%')


    AND operation_type = #{operationType}


    AND operation_module = #{operationModule}


    AND status = #{status}


    AND create_date >= #{startTime}


    AND create_date <= #{endTime}

ORDER BY create_date DESC

    LIMIT #{offset}, #{pageSize}

